function yamlList(values) { return JSON.stringify(values); }

function render(spec) {
  const frontmatter = [
    `title: ${JSON.stringify(spec.title)}`,
    `meta_title: ${JSON.stringify(spec.title)}`,
    `meta_description: ${JSON.stringify(spec.summary)}`,
    `slug: ${JSON.stringify(spec.slug)}`,
    `summary: ${JSON.stringify(spec.summary)}`,
    `category: ${JSON.stringify(spec.category)}`,
    `difficulty: ${JSON.stringify(spec.difficulty)}`,
    `estimated_time: ${JSON.stringify(spec.time)}`,
    `prerequisites: ${yamlList(spec.prereq)}`,
    `excel_versions: ${yamlList(spec.versions)}`,
    `tags: ${yamlList(spec.tags)}`,
    `date: ${JSON.stringify(date)}`,
    `updated_date: ${JSON.stringify(date)}`,
    "featured: false",
    "draft: true",
    `related_templates: ${yamlList(spec.related.templates)}`,
    `related_guides: ${yamlList(spec.related.guides)}`,
    `related_formulas: ${yamlList(spec.related.formulas)}`,
    `related_troubleshooting: ${yamlList(spec.related.troubleshooting)}`,
  ].join("\n");
  const steps = spec.steps.map((step, index) => `${index + 1}. ${step}`).join("\n");
  const failures = spec.failures.map((item) => `- ${item}`).join("\n");
  return `---\n${frontmatter}\n---\n\n## Masalah yang Diselesaikan\n\n${spec.problem}\n\n## Hasil yang Diharapkan\n\n${spec.result}\n\n## Prasyarat\n\n${spec.prereq.map((item) => `- ${item}`).join("\n")}\n\n## Contoh Input\n\n\`\`\`text\n${spec.sample}\n\`\`\`\n\n## Langkah Praktik\n\n${steps}\n\n## Mengapa Ini Bekerja\n\n${spec.why}\n\n## Kesalahan Umum\n\n${failures}\n\n## Diagnosis\n\n${spec.diagnostics}\n\n## Cara Memperbaiki\n\n${spec.correction}\n\n## Kompatibilitas dan Alternatif Versi Lama\n\n${spec.compatibility}\n\nAlternatif untuk Excel lama: ${spec.alternative}\n\n## Batasan\n\n${spec.limit}\n\n## Langkah Praktis Berikutnya\n\n${spec.next}\n\n## Related Resources\n\n- Template: ${spec.related.templates.map((x) => `[${x}](/templates/)`).join(", ")}\n- Panduan: ${spec.related.guides.map((x) => `[${x}](/panduan/)`).join(", ")}\n- Rumus: ${spec.related.formulas.map((x) => `[${x}](/rumus-excel/)`).join(", ")}\n- Troubleshooting: ${spec.related.troubleshooting.map((x) => `[${x}](/masalah-excel/)`).join(", ")}\n\nGoogle Sheets: ${spec.compatibility.includes("Google Sheets") ? "uji ulang sintaks dan perilaku karena tidak semua fitur Excel tersedia." : "artikel ini berfokus pada Excel; jangan menganggap perilaku Google Sheets identik."}\n`;
}

await mkdir(guideDir, { recursive: true });
for (const guide of guides) {
  await writeFile(path.join(guideDir, `${guide.slug}.md`), render(guide), "utf8");
}
console.log(`Rewrote ${guides.length} draft guides.`);
